const CLIENT_ID = process.env.ITWIN_SERVICE_APP_CLIENT_ID;
const CLIENT_SECRET = process.env.ITWIN_SERVICE_APP_CLIENT_SECRET;

const ITWIN_API_URL = "https://api.bentley.com";

if (!CLIENT_ID || !CLIENT_SECRET) {
  console.error("Missing client id or secret");
  exit(1);
}

/** @import {Share} from './iTwinShareUpdater.js' */

/**
 * @param {string} accessToken
 */
async function getMyInfo(accessToken) {
  // TODO: remove
  const resp = await fetch(`${ITWIN_API_URL}/users/me`, {
    headers: {
      Authorization: `Bearer ${accessToken}`,
      Accept: "application/vnd.bentley.itwin-platform.v1+json",
    },
  });
  const result = await resp.json();
  return result.user;
}

/**
 * @param {string} accessToken
 * @returns {Promise<Itwin[]>}
 */
async function getItwinsWithAccess(accessToken) {
  // TODO: remove
  const resp = await fetch(`${ITWIN_API_URL}/itwins`, {
    headers: {
      Authorization: `Bearer ${accessToken}`,
      Accept: "application/vnd.bentley.itwin-platform.v1+json",
    },
  });
  const result = await resp.json();
  return result.iTwins;
}

/**
 * @param {string} token
 */
async function listMyItwins(token) {
  const me = await getMyInfo(token);
  console.log(`Logged in as: ${me.givenName} (${me.email})`);

  const itwins = await getItwinsWithAccess(token);
  console.log("                                  ID - Name (Number)");
  itwins.forEach((itwin) => {
    console.log(`${itwin.id} - ${itwin.displayName} (${itwin.number})`);
  });
}

async function listSharesForItwin(itwinId, token) {
  const shares = await getShares(itwinId, token);
  /** @type {Share[]} */
  const sorted = shares.toSorted((a, b) =>
    a.expiration.localeCompare(b.expiration),
  );
  console.log("Shares for itwin:", itwinId);
  sorted.forEach((share) => {
    console.log(`${share.expiration} - ${share.id}: ${share.shareKey}`);
  });
}

